Функция ПолучитьСуммарныйДолгКонтрагента(Контрагент) Экспорт
	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	ЕСТЬNULL(СУММА(ВзаиморасчетыОстатки.Сумма), 0) КАК СуммаДолга
		|ИЗ
		|	РегистрНакопления.Взаиморасчеты.Остатки(, Договор.Владелец = &Контрагент И Сумма > 0) КАК ВзаиморасчетыОстатки";
	Запрос.УстановитьПараметр("Контрагент", Контрагент);
	Выборка = Запрос.Выполнить().Выбрать();
	Если Выборка.Следующий() Тогда
		Возврат Выборка.СуммаДолга;
	КонецЕсли;
	Возврат 0;
КонецФункции
